case class UrlRequest(url: String)
case class UrlResponse(status: Int, content: String, headers: Map[String, String])

object UrlRequest {
  implicit val urlRequestFormat: RootJsonFormat[UrlRequest] = jsonFormat1(UrlRequest)
  implicit val urlResponseFormat: RootJsonFormat[UrlResponse] = jsonFormat3(UrlResponse)
