object WebhookProxyService {
  implicit val system: ActorSystem = ActorSystem("webhook-proxy")
  implicit val materializer: ActorMaterializer = ActorMaterializer()
  implicit val executionContext: ExecutionContextExecutor = system.dispatcher
  
  val http = Http()
  
  val allowedHosts = Set("api.partner1.com", "api.partner2.com", "api.partner3.com")
  val allowedProtocols = Set("http", "https")
  
  def isValidUrl(url: String): Boolean = {
    try {
      val uri = new URI(url)
      val host = uri.getHost
      val protocol = uri.getScheme
      
      allowedProtocols.contains(protocol) && 
      (host == null || allowedHosts.contains(host) || 
       allowedHosts.exists(_.endsWith(host)))
    } catch {
      case _: Exception => false
    }
  }
  
  def isAllowedHost(host: String): Boolean = {
    allowedHosts.contains(host) || 
    allowedHosts.exists(_.endsWith(host))
  }
  
  def isLocalhost(host: String): Boolean = {
    val inetAddress = InetAddress.getByName(host)
    inetAddress.isLoopbackAddress || 
    inetAddress.isSiteLocalAddress || 
    inetAddress.isAnyLocalAddress
  }
  
  def validateUrl(url: String): Either[String, Uri] = {
    try {
      val uri = Uri(url)
      val host = uri.authority.host.toString()
      
      if (!isValidUrl(url)) {
        Left("Invalid URL or host not allowed")
      } else if (isLocalhost(host)) {
        Left("Localhost access not allowed")
      } else {
        Right(uri)
      }
    } catch {
      case _: Exception => Left("Invalid URL format")
    }
  }
  
  val route: Route = 
    path("proxy") {
      post {
        entity(as[UrlRequest]) { request =>
          validateUrl(request.url) match {
            case Right(uri) =>
              val httpRequest = HttpRequest(uri = uri)
              onComplete(http.singleRequest(httpRequest)) {
                case Success(response) =>
                  val headers = response.headers.map(h => h.name -> h.value).toMap
                  val content = response.entity.dataBytes
                    .map(_.utf8String)
                    .runFold("")(_ + _)
                    .map(_.toString)
                  onComplete(content) { 
                    case Success(contentString) =>
                      complete(UrlResponse(response.status.intValue(), contentString, headers))
                    case Failure(ex) =>
                      complete(StatusCodes.InternalServerError -> ex.getMessage)
                  }
                case Failure(ex) =>
                  complete(StatusCodes.InternalServerError -> ex.getMessage)
              }
            case Left(error) =>
              complete(StatusCodes.BadRequest -> error)
          }
        }
      }
    }
  
  def main(args: Array[String]): Unit = {
    val bindingFuture = Http().bindAndHandle(route, "localhost", 8080)
    println("Server online at http://localhost:8080/")
  }
}